+import { join } from "@std/path";
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+/** Load and normalize configuration files for a command. */
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const searchPaths = options.searchPaths ?? [Deno.cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  const values: Record<string, unknown> = {};
+  let path: string | undefined;
+
+  for (const searchPath of searchPaths) {
+    for (const format of formats) {
+      const candidate = join(
+        searchPath,
+        format === ".rc" ? `.${options.name}rc` : `${options.name}${format}`,
+      );
+
+      try {
+        const content = await Deno.readTextFile(candidate);
+        const parsed = parseConfig(content, candidate, format, options.parser);
+        const flattened = flattenConfig(parsed);
+
+        if (!path) path = candidate;
+        for (const [key, value] of Object.entries(flattened)) {
+          // Earlier search paths and formats have precedence when merging.
+          if (!(key in values)) values[key] = value;
+        }
+
+        if (!options.mergeConfigs) return { path, values };
+      } catch (error) {
+        if (error instanceof Deno.errors.NotFound) continue;
+        if (error instanceof ConfigParseError) throw error;
+        throw new ConfigParseError(candidate, error);
+      }
+    }
+  }
+
+  return { path, values };
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const value = parser
+      ? parser(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : JSON.parse(content);
+
+    if (!isPlainObject(value)) throw new TypeError("Expected a plain object.");
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+
+    const index = trimmed.indexOf("=");
+    if (index === -1) throw new TypeError("Expected key=value pair.");
+
+    const key = trimmed.slice(0, index).trim();
+    let value = trimmed.slice(index + 1).trim();
+    if (!key) throw new TypeError("Expected a configuration key.");
+
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new TypeError("Unterminated quoted value.");
+      }
+      value = value.slice(1, -1);
+    }
+
+    result[key] = coerceRcValue(value);
+  }
+
+  return result;
+}
+
+function coerceRcValue(value: string): string | boolean | number {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  if (value.trim() && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:e[-+]?\\d+)?$/i.test(value)) {
+    return Number(value);
+  }
+  return value;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [rawKey, item] of Object.entries(value)) {
+    const key = toCamelCase(rawKey);
+    const path = prefix ? `${prefix}.${key}` : key;
+    if (isPlainObject(item)) {
+      Object.assign(result, flattenConfig(item, path));
+    } else {
+      result[path] = item;
+    }
+  }
+  return result;
+}
+
+function toCamelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char: string) => char.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (value === null || typeof value !== "object" || Array.isArray(value)) return false;
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
